func:
// Filtrace bazénu v4 — minimální denní doba dle TEPLOTY VODY (§10.1, §10.2)
// Hard cut-off: poolT < filtrace_pool_temp_min (2 °C) → filtrace VŮBEC neběží.
// Studená voda (poolT < threshold − hyst): MIN_COLD min/den (60).
// Teplá voda  (poolT ≥ threshold):           MIN_WARM min/den (120).
// Mezi prahy se drží předchozí stav (flow.filt_temp_band) — proti oscilaci.
// LETNI/ZIMNI REZIM JIZ NENI VSTUPEM TOHOTO ROZHODNUTI.

// === Konfigurace z fve_config ===
var cfg = global.get("fve_config") || {};
var S_ON      = cfg.filtrace_surplus_on_w        || 2500;
var S_OFF     = cfg.filtrace_surplus_off_w       || 1500;
var T_MIN     = cfg.filtrace_pool_temp_min       || 2;     // §10.1 hard cut-off
var T_THRESH  = cfg.filtrace_pool_temp_threshold_c || 10;  // §10.2 přepínač studená/teplá
var T_HYST    = cfg.filtrace_pool_temp_hysterese_c || 1;   // §10.2 hystereze
var MIN_COLD  = cfg.filtrace_min_studena_min     || 60;
var MIN_WARM  = cfg.filtrace_min_tepla_min       || 120;
var DEAD      = cfg.filtrace_deadline_h          || 23;
var ANTI      = (cfg.filtrace_anti_cycle_min     || 10) * 60 * 1000;
var SOC_LOW   = cfg.filtrace_soc_low             || 40;
var SOLAR_OK  = cfg.filtrace_solar_ok_kwh        || 10;
var MIN_RUN_M = cfg.filtrace_min_run_min         || 15;
var TICK = 2;

// === Vstupní data z msg ===
var fOn = msg.filtraceState === "on";
var autoOn = (msg.automatizovatFiltrace === "on");
if (msg.automatizovatFiltrace === undefined || msg.automatizovatFiltrace === null || msg.automatizovatFiltrace === "") {
    var _autoE = global.get("homeassistant.homeAssistant.states['input_boolean.automatizovat_filtraci_v_bazenu']") || {};
    autoOn = _autoE.state === "on";
}
var surplus = parseFloat(msg.solarSurplus) || 0;
var soc = parseFloat(msg.batterySoc) || 0;

// NIBE kompresor aktivní → filtrace pauza (nižší priorita než NIBE)
var nibeCompE = global.get("homeassistant.homeAssistant.states['binary_sensor.nibe_kompresory_aktivni_binarni']") || {};
var nibeComp = nibeCompE.state === "on";

// §4.10: Záporná nákupní cena — filtraci jako nejnižší prioritu spotřebiče
var isZapNak = (global.get("fve_current_mode") || "") === "zaporna_nakupni_cena";
var gridE = global.get("homeassistant.homeAssistant.states['sensor.spotreba_ze_site']") || {};
var gridDraw = parseFloat(gridE.state) || 0;
var maxGrid = cfg.max_spotreba_sit_w || 22000;
var FILT_W = 2500;
var hasHeadroom = (maxGrid - gridDraw) >= FILT_W;

// Teplota bazénu z HA
var tE = global.get("homeassistant.homeAssistant.states['sensor.hp2551ae_pro_v2_1_0_temperature_1']") || {};
var poolT = parseFloat(tE.state);
if (isNaN(poolT)) poolT = 0;

// === Pásmo teploty s hysterezí (§10.2) ===
// "tepla" pokud poolT ≥ T_THRESH; "studena" pokud poolT < T_THRESH - T_HYST.
// Mezi: drž předchozí stav. Při startu (žádný stav): podle T_THRESH bez hystereze.
var band = flow.get("filt_temp_band") || "";
if (poolT >= T_THRESH) {
    band = "tepla";
} else if (poolT < (T_THRESH - T_HYST)) {
    band = "studena";
} else if (band === "") {
    band = (poolT >= T_THRESH) ? "tepla" : "studena";
}
flow.set("filt_temp_band", band);

// Minimální požadavek dle pásma — hard cut-off (§10.1) nuluje minimum (čidlo poolT==0 = neznámá hodnota → ignoruj cut-off)
var coldLock = (poolT < T_MIN && poolT > 0);
var minReq = coldLock ? 0 : (band === "tepla" ? MIN_WARM : MIN_COLD);

// FVE plán
var planData = global.get("fve_plan") || {};
var plan = planData.plan || [];
var cur = plan.length > 0 ? plan[0] : {};
var mode = cur.mode || "setrit";
var pLvl = cur.priceLevel || 0;

// Solární předpověď — zbývající dnes
var remE = global.get("homeassistant.homeAssistant.states['sensor.energy_production_today_remaining_3']") || {};
var solRemain = parseFloat(remE.state) || 0;

// === Čas ===
var d = new Date();
var tp = d.toLocaleTimeString("en-GB", {timeZone: "Europe/Prague", hour12: false}).split(":");
var hr = parseInt(tp[0]), mn = parseInt(tp[1]);
var nowM = hr * 60 + mn;
var now = d.getTime();

// === Denní tracker ===
var today = d.toLocaleDateString("en-CA", {timeZone: "Europe/Prague"});
var sDate = flow.get("filt_date") || "";
var run = flow.get("filt_run") || 0;
var newDay = today !== sDate;

var isRestart = sDate === "";
if (isRestart) {
    var _saved = {};
    try { _saved = JSON.parse(fs.readFileSync("/homeassistant/filt_counter.json", "utf8")); } catch(e) { _saved = {}; }
    if (_saved.date === today) { run = _saved.run || 0; }
    flow.set("filt_date", today);
    flow.set("filt_run", run);
} else if (newDay) {
    run = 0;
    flow.set("filt_date", today);
    flow.set("filt_run", 0);
}
if (fOn) {
    run += TICK;
    flow.set("filt_run", run);
}
try { fs.writeFileSync("/homeassistant/filt_counter.json", JSON.stringify({date: today, run: run})); } catch(e) {}
global.set("filt_persist", {date: today, run: run});

// Min continuous run tracking (zákon 10.1)
var contStart = flow.get("filt_cont_start") || 0;
if (fOn && !(flow.get("filt_was_on"))) { contStart = now; flow.set("filt_cont_start", now); }
flow.set("filt_was_on", fOn);
var contRunMin = fOn ? (now - contStart) / 60000 : 0;
var minRunOk = !fOn || contRunMin >= MIN_RUN_M;

// === Analýza FVE plánu ===
var futureSolar = 0;
for (var i = 1; i < plan.length; i++) {
    if (plan[i].isSolarHour) futureSolar++;
}
var hasFutureSolar = futureSolar > 0 || solRemain >= SOLAR_OK;

// === Výpočty ===
var rem = Math.max(0, minReq - run);
var met = rem <= 0;
var minToDead = Math.max(0, (DEAD * 60) - nowM);
var urgent = !met && minReq > 0 && minToDead <= (rem + 15);

// Podmínky
var gSurp = surplus >= S_ON;
var oSurp = surplus >= S_OFF;
var inSetrit = mode === "setrit";
var inNormal = mode === "normal";
var lowSOC = soc < SOC_LOW;

// Anti-cycling
var lastOn = flow.get("filt_on_ts") || 0;
var lastOff = flow.get("filt_off_ts") || 0;

// === ROZHODOVÁNÍ ===
var act = "none", rsn = "";

if (autoOn) {
if (!fOn) {
    // 0a. Hard cut-off: pool teplota pod T_MIN → filtrace NESMÍ běžet (§10.1)
    if (coldLock) {
        global.set("filtrace_status", {run: run, minReq: minReq, met: true, remaining: 0});
        node.status({fill: "blue", shape: "ring", text: "Pool " + poolT + "°C < " + T_MIN + "°C → freeze lock"});
        return [null, null, null, null];
    }
    // 0. NIBE kompresor aktivní → nepouštět filtraci (§4.10: bypass v záporné ceně)
    if (nibeComp && !isZapNak) {
        global.set("filtrace_status", {run: run, minReq: minReq, met: run >= minReq, remaining: Math.max(0, minReq - run)});
        node.status({fill: "grey", shape: "ring", text: "NIBE komp. běží → pauza " + run + "/" + minReq + "m"});
        return [null, null, null, null];
    }
    // §4.10: Záporná nákupní cena — filtrovat pokud prostor pod jističem
    if (isZapNak && hasHeadroom) {
        act = "on";
        rsn = "Záporná cena! Volno:" + Math.round(maxGrid - gridDraw) + "W";
    }
    // 1. Solární přebytek → ON (zdarma)
    else if (gSurp && !met) {
        act = "on";
        rsn = "Solar +" + Math.round(surplus) + "W";
    }
    // 2. Nesplněno min + ŠETŘIT + žádný budoucí solar → ON
    else if (!met && minReq > 0 && inSetrit && !hasFutureSolar) {
        act = "on";
        rsn = "Šetřit L" + pLvl + ", žádný solar, zbývá " + rem + "min";
    }
    // 3. URGENT + ŠETŘIT → ON
    else if (urgent && inSetrit) {
        act = "on";
        rsn = "Deadline! " + rem + "min do " + DEAD + ":00 (šetřit)";
    }
    // 4. URGENT + NORMAL + SOC OK → ON
    else if (urgent && inNormal && !lowSOC) {
        act = "on";
        rsn = "Deadline! " + rem + "min (normal, SOC " + soc + "%)";
    }
    // 5. SUPER URGENT (< 20 min do deadline) → ON za každou cenu
    else if (!met && minReq > 0 && minToDead <= 20 && minToDead > 0) {
        act = "on";
        rsn = "EMERGENCY! " + minToDead + "min do deadline";
    }

    if (act === "on" && (now - lastOff) < ANTI) {
        act = "none"; rsn = "";
    }

} else {
    // --- BĚŽÍ ---
    // 0a. Hard cut-off → OFF
    if (coldLock) {
        act = "off"; rsn = "Pool " + poolT + "°C < " + T_MIN + "°C";
    }
    // 0. NIBE kompresor aktivní → vypnout filtraci (§4.10: bypass v záporné ceně)
    if (nibeComp && !isZapNak) {
        act = "off"; rsn = "NIBE komp. běží";
    }
    // §4.10: Záporná — OFF jen pokud jistič plný
    if (isZapNak && !hasHeadroom) {
        act = "off";
        rsn = "Záporná: jistič " + Math.round(gridDraw) + "/" + maxGrid + "W";
    }
    // 1. Minimum splněno → OFF (zákon 10.1; §4.10: v záporné ceně neplatí)
    else if (met && !isZapNak) {
        act = "off";
        rsn = "OK " + run + "/" + minReq + "min";
    }
    // 2. NORMAL mód + nízký SOC + žádný přebytek → OFF (ochrana baterie)
    else if (!oSurp && inNormal && lowSOC) {
        act = "off";
        rsn = "Ochrana bat! SOC:" + soc + "%, mode:" + mode;
    }
    // 3. Min nesplněno + přebytek klesl + budoucí solar → PAUZA
    else if (!met && minReq > 0 && !oSurp && hasFutureSolar && !urgent) {
        act = "off";
        rsn = "Pauza → čeká solar (" + solRemain.toFixed(0) + "kWh rem)";
    }
    // 4. Min nesplněno + přebytek klesl + není šetřit + není urgent → PAUZA
    else if (!met && minReq > 0 && !oSurp && !inSetrit && !urgent) {
        act = "off";
        rsn = "Pauza (normal mód, SOC:" + soc + "%)";
    }
    // Pokud minReq=0 (cold-lock) a žádný přebytek → OFF (§4.10: ne v záporné ceně)
    else if (minReq === 0 && !oSurp && !isZapNak) {
        act = "off";
        rsn = "Bez minima, přebytek " + Math.round(surplus) + "W";
    }

    // Min continuous run protection (zákon 10.1: nepřerušovat pokud < MIN_RUN_M min)
    if (act === "off" && !minRunOk && !met && !coldLock) {
        act = "none"; rsn = "";
    }
    if (act === "off" && (now - lastOn) < ANTI && !nibeComp && !met) {
        act = "none"; rsn = "";
    }
}
} else {
    rsn = "Ruční režim (měření času)";
}

// Track transitions
if (act === "on") flow.set("filt_on_ts", now);
if (act === "off") flow.set("filt_off_ts", now);

// === Status ===
var bandTag = (band === "tepla") ? "T" : "S";  // T=teplá, S=studená
var st = bandTag + (fOn ? "•ON" : "•OFF");
st += " " + run + "/" + minReq + "m";
st += " ΔP:" + Math.round(surplus) + "W";
st += " SOC:" + soc + "% " + mode + "/L" + pLvl;
st += " T:" + poolT + "°C";
if (fOn) st += " CR:" + contRunMin.toFixed(0) + "/" + MIN_RUN_M + "m";
if (hasFutureSolar) st += " ☀" + solRemain.toFixed(0) + "kWh";
if (isZapNak) st += " 💰ZAP G:" + Math.round(gridDraw) + "/" + maxGrid + "W";
if (act !== "none") st += " → " + act + ": " + rsn;
var cl = act === "on" ? "blue" : act === "off" ? "yellow" : "green";
node.status({fill: cl, shape: "dot", text: st});

// === Výstupy [0]=ON, [1]=OFF, [2]=flag_on, [3]=flag_off ===
var out = [null, null, null, null];
if (act === "on") out[0] = {payload: "on", reason: rsn};
if (act === "off") out[1] = {payload: "off", reason: rsn};
if (act === "on" && gSurp) out[2] = {payload: "on"};
if (newDay) out[3] = {payload: "off"};

global.set("filtrace_status", {run: run, minReq: minReq, met: met, remaining: Math.max(0, minReq - run)});

return out;
